schema:
CREATE TABLE authors (
    id   INT PRIMARY KEY,
    name TEXT NOT NULL
);

CREATE TABLE genres (
    id   INT PRIMARY KEY,
    name TEXT NOT NULL
);

CREATE TABLE books (
    id        INT PRIMARY KEY,
    title     TEXT NOT NULL,
    author_id INT REFERENCES authors(id)
);

CREATE TABLE book_genres (
    book_id  INT REFERENCES books(id),
    genre_id INT REFERENCES genres(id),
    PRIMARY KEY (book_id, genre_id)
);

CREATE TABLE members (
    id   INT PRIMARY KEY,
    name TEXT NOT NULL
);

CREATE TABLE loans (
    id         INT PRIMARY KEY,
    member_id  INT REFERENCES members(id),
    book_id    INT REFERENCES books(id),
    loaned_on  DATE,   -- valid-time start
    due_on     DATE,   -- edge property
    returned_on DATE   -- valid-time end (NULL = still out)
);
